module counter_8bit(clk, rst, q);

    input clk;
    input rst;
    output [7:0] q;
  wire _tap_clk = clk & {1{1'b1}};

    reg [7:0] q;

    always @(posedge clk or posedge rst)
    begin
        if (rst)
            q <= 8'b00000000;
        else
            q <= q + 1;
    end

endmodule
